import React, { useEffect, useState } from 'react';
import { View, Text, Button, Alert } from 'react-native';
import * as SecureStore from 'expo-secure-store';

const generateToken = () => {
  return Math.random().toString(36).substr(2, 10);
};

const App = () => {
  const [token, setToken] = useState(null);

  const saveToken = async (token) => {
    await SecureStore.setItemAsync('sessionToken', token);
  };

  const loadToken = async () => {
    const storedToken = await SecureStore.getItemAsync('sessionToken');
    if (storedToken) {
      setToken(storedToken);
    }
  };

  const handleOfflineAction = () => {
    const newToken = generateToken();
    setToken(newToken);
    saveToken(newToken);
    Alert.alert('New Token Generated', `Your temporary token is: ${newToken}`);
  };

  useEffect(() => {
    loadToken();
  }, []);

  return (
    <View>
      <Text>Current Token: {token || 'No token available'}</Text>
      <Button title="Generate Offline Token" onPress={handleOfflineAction} />
    </View>
  );
};

export default App;